 1	import * as React from 'react';
 2	import { Label, Tooltip, TooltipPosition } from '@patternfly/react-core';
 3	import { t } from 'i18next';
 4	
 5	type AmbientLabelProps = {
 6	  style?: React.CSSProperties;
 7	  tooltip?: string;
 8	};
 9	
10	export const AmbientBadge: React.FC<AmbientLabelProps> = (props: AmbientLabelProps) => {
11	  const tooltipContent = <div style={{ textAlign: 'left' }}>{props.tooltip}</div>;
12	
13	  const iconComponent = (
14	    <Label style={{ marginLeft: '0.5rem', ...props.style }} color="blue" isCompact data-test="ambient-badge">
15	      {t('Ambient')}
16	    </Label>
17	  );
18	
19	  return props.tooltip ? (
20	    <Tooltip key="tooltip_ambient_label" position={TooltipPosition.right} content={tooltipContent}>
21	      {iconComponent}
22	    </Tooltip>
23	  ) : (
24	    iconComponent
25	  );
26	};

